module RefModule(CLK, LOAD, INIT_VAL, COUNT);
input CLK, LOAD;
input [3:0] INIT_VAL;
output reg [3:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (LOAD)
        COUNT <= INIT_VAL;
    else
        COUNT <= COUNT + 1;
end

endmodule
